K::cmp_properties();
    if 0 <= r1 < self_.keys@.len()
        && self_.greatest_lower_bound_spec(iter, KeyIterator::new_spec(self_.keys@[r1 as int]))
        && 0 <= r2 < self_.keys@.len()
        && self_.greatest_lower_bound_spec(iter, KeyIterator::new_spec(self_.keys@[r2 as int]))
    {
        let k1 = self_.keys@[r1 as int];
        let k2 = self_.keys@[r2 as int];
        let g1 = KeyIterator::new_spec(k1);
        let g2 = KeyIterator::new_spec(k2);

        assert(g1.k.is_Some() && g1.k.get_Some_0() == k1);
        assert(g2.k.is_Some() && g2.k.get_Some_0() == k2);

        // From GLB spec part 1: glb == iter || glb.lt_spec(iter)
        assert(g1 == iter || g1.lt_spec(iter));
        assert(g2 == iter || g2.lt_spec(iter));

        // From GLB spec part 3 (when !iter.is_end), glb.k.is_Some and contains_key(glb.key)
        if !iter.is_end_spec() {
            assert(self_@.contains_key(k1));
            assert(self_@.contains_key(k2));
        }

        if g1 != g2 {
            // Case A: g1 == iter, g2.lt_spec(iter)
            if g1 == iter {
                assert(!iter.is_end_spec());
                assert(g2.lt_spec(iter));
                // From GLB spec for g2, exists hi with gap and between
                let hi = choose|hi: KeyIterator<K>|
                    #[trigger] self_.gap(g2, hi) && #[trigger] KeyIterator::between(g2, iter, hi);
                assert(self_.gap(g2, hi) && KeyIterator::between(g2, iter, hi));
                // between(g2, iter, hi) means iter.lt_spec(hi)
                assert(iter.lt_spec(hi));
                // gap: forall ki, g2 < ki < hi ==> !contains_key(*ki.get())
                // Take ki = iter. iter has Some(k1) since g1 == iter has Some.
                assert(iter.k.is_Some());
                assert(*iter.get() == k1);
                assert(self_@.contains_key(*iter.get()));
                assert(g2.lt_spec(iter) && iter.lt_spec(hi));
                assert(!self_@.contains_key(*iter.get()));
                assert(false);
            } else if g2 == iter {
                // Symmetric to above
                assert(!iter.is_end_spec());
                assert(g1.lt_spec(iter));
                let hi = choose|hi: KeyIterator<K>|
                    #[trigger] self_.gap(g1, hi) && #[trigger] KeyIterator::between(g1, iter, hi);
                assert(self_.gap(g1, hi) && KeyIterator::between(g1, iter, hi));
                assert(iter.lt_spec(hi));
                assert(iter.k.is_Some());
                assert(*iter.get() == k2);
                assert(self_@.contains_key(*iter.get()));
                assert(g1.lt_spec(iter) && iter.lt_spec(hi));
                assert(!self_@.contains_key(*iter.get()));
                assert(false);
            } else {
                // Both lt_spec(iter)
                assert(g1.lt_spec(iter));
                assert(g2.lt_spec(iter));

                // Need contains_key for both, also when iter is end
                // When iter is end, we still need contains_key. 
                // Use the fact that keys[r_i] in keys@ implies in dom.
                // This relies on map_valid which is closed.
                assert(self_@.contains_key(k1));
                assert(self_@.contains_key(k2));

                // iter.above(k_i) holds
                assert(iter.above(k1));
                assert(iter.above(k2));

                // Apply forall for g1 at k = k2
                assert(KeyIterator::new_spec(k2) != g1);
                assert(g1.above(k2));
                // g1 has Some, so g1.above(k2) means k2 < k1
                assert(k2.cmp_spec(k1).lt());

                // Apply forall for g2 at k = k1
                assert(KeyIterator::new_spec(k1) != g2);
                assert(g2.above(k1));
                assert(k1.cmp_spec(k2).lt());

                // contradiction by asymmetry
                assert(false);
            }
        }
        // Now g1 == g2, hence k1 == k2.
        assert(g1 == g2);
        assert(k1 == k2);

        // Use sorted/no_duplicates of keys to derive r1 == r2.
        if r1 < r2 {
            assert(self_.keys@[r1 as int].cmp_spec(self_.keys@[r2 as int]).lt());
            assert(false);
        } else if r2 < r1 {
            assert(self_.keys@[r2 as int].cmp_spec(self_.keys@[r1 as int]).lt());
            assert(false);
        }
        assert(r1 == r2);
    }
